import java.io.*;
import java.net.*;

public class P2PNode {
    private int port;
    private ServerSocket serverSocket;

    public P2PNode(int port) {
        this.port = port;
    }

    public void start() throws IOException {
        // Act as server: listen for incoming requests
        serverSocket = new ServerSocket(port);
        System.out.println("P2P Node listening on port " + port);

        while (true) {
            Socket clientSocket = serverSocket.accept();
            handleRequest(clientSocket);
        }
    }

    // Act as client: send request to another peer
    public void sendRequest(String host, int remotePort, String message) 
        throws IOException {
        Socket socket = new Socket(host, remotePort);
        PrintWriter out = new PrintWriter(socket.getOutputStream(), true);
        BufferedReader in = new BufferedReader(
            new InputStreamReader(socket.getInputStream()));

        out.println(message);
        String response = in.readLine();
        System.out.println("Response: " + response);

        socket.close();
    }

    private void handleRequest(Socket clientSocket) throws IOException {
        // Process request and send response
        BufferedReader in = new BufferedReader(
            new InputStreamReader(clientSocket.getInputStream()));
        PrintWriter out = new PrintWriter(
            clientSocket.getOutputStream(), true);

        String request = in.readLine();
        String response = "Processed: " + request;
        out.println(response);

        clientSocket.close();
    }

    public static void main(String[] args) throws IOException {
        P2PNode node = new P2PNode(6000);
        node.start();
    }
}
